import React, { useState } from 'react';
import './FloatingNewsletter.css';

const BASE_URL = 'http://localhost:4000'; // zameni sa tvojim backend URL-om ako deployujes

export default function FloatingNewsletter() {
  const [email, setEmail] = useState('');
  const [visible, setVisible] = useState(true);

  const handleSubscribe = async () => {
    if (!email || !email.includes('@')) {
      alert('Please enter a valid email address.');
      return;
    }

    try {
      const res = await fetch(`${BASE_URL}/subscribe`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email }),
      });

      if (res.ok) {
        alert('Subscribed successfully! 💌');
        setEmail('');
      } else {
        alert('Subscription failed. Try again.');
      }
    } catch (err) {
      console.error('Subscription error:', err);
      alert('Server error. Try again later.');
    }
  };

  if (!visible) return null;

  return (
    <div className="floating-newsletter">
      <button className="close-btn" onClick={() => setVisible(false)}>
        &times;
      </button>
      <h3 className="newsletter-title">Join our newsletter 💌</h3>
      <div className="newsletter-row">
        <input
          type="email"
          placeholder="Enter your email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />
        <button onClick={handleSubscribe}>Subscribe</button>
      </div>
    </div>
  );
}
